/**
 * DASHBOARD-STRATEGIE-CLI
 * Demonstrates: 1-2 centralized, automated dashboards > 1,000 fragmented mini-dashboards
 * Audience: Management & Developers
 * Scope: ~2,000 words, high information density, >=85% automation
 */

import fs from 'fs';
import path from 'path';

const C = {
  reset: '\x1b[0m', bold: '\x1b[1m', dim: '\x1b[2m',
  red: '\x1b[31m', green: '\x1b[32m', yellow: '\x1b[33m',
  blue: '\x1b[34m', cyan: '\x1b[36m', gray: '\x1b[90m',
};

function line(char, len) { return char.repeat(len); }

function box(title, lines, color = 'cyan') {
  const colorCode = C[color] || C.cyan;
  const w = Math.max(title.length + 4, ...lines.map(l => l.replace(/\x1b\[[0-9;]*m/g, '').length)) + 4;
  const top = '┌' + line('─', w - 2) + '┐';
  const mid = '│ ' + C.bold + colorCode + title + C.reset + ' '.repeat(w - 4 - title.length) + ' │';
  const bot = '└' + line('─', w - 2) + '┘';
  const body = lines.map(l => {
    const plain = l.replace(/\x1b\[[0-9;]*m/g, '');
    return '│ ' + l + ' '.repeat(Math.max(0, w - 4 - plain.length)) + ' │';
  });
  return [top, mid, ...body, bot].join('\n');
}

